import React, { useEffect } from 'react';

function ScrollController() {
  useEffect(() => {
    const handleScroll = () => {
      var sections = document.querySelectorAll("section");

      sections.forEach(function(section) {
        var position = section.getBoundingClientRect().top;
        var screenHeight = window.innerHeight;

        if (position < screenHeight / 2) {
          section.classList.remove("slide-from-left");
          section.classList.remove("slide-from-right");
          section.classList.add("slide-from-center");
        } else {
          var index = parseInt(section.id.split("-")[1]);
          if (index % 2 === 0) {
            section.classList.remove("slide-from-right");
            section.classList.add("slide-from-left");
          } else {
            section.classList.remove("slide-from-left");
            section.classList.add("slide-from-right");
          }
        }
      });
    };

    document.addEventListener("DOMContentLoaded", handleScroll);
    window.addEventListener("scroll", handleScroll);

    return () => {
      document.removeEventListener("DOMContentLoaded", handleScroll);
      window.removeEventListener("scroll", handleScroll);
    };
  }, []);

  return null;
}

export default ScrollController;
